import React, { useState } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut } from 'lucide-react'; // Added LogOut icon

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [message, setMessage] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false); // Track login state

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/api/auth/login', formData);
      setMessage(`Welcome back, ${res.data.user.name}!`);
      localStorage.setItem('token', res.data.token);
      setIsLoggedIn(true); // User is now logged in
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Login Failed');
    }
  };

  // 1. Put the Logout Function here
  const handleLogout = () => {
    localStorage.removeItem('token');
    setMessage('You have been logged out.');
    setIsLoggedIn(false);
    setFormData({ email: '', password: '' });
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <div className="p-8 bg-white shadow-2xl rounded-2xl w-96 border-t-4 border-blue-600">
        
        {/* Header Icon */}
        <div className="flex justify-center mb-6 text-blue-600">
          <LogIn size={48} />
        </div>
        <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">QuadSolutions Login</h2>
        
        {/* 2. ONLY SHOW THE FORM IF NOT LOGGED IN */}
        {!isLoggedIn ? (
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="relative">
              <Mail className="absolute left-3 top-3 text-gray-400" size={20} />
              <input
                type="email"
                placeholder="Email Address"
                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                required
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
              <input
                type="password"
                placeholder="Password"
                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                required
              />
            </div>
            <button className="w-full bg-blue-600 text-white py-2 rounded-lg font-semibold hover:bg-blue-700 transition duration-300">
              Sign In
            </button>
          </form>
        ) : (
          /* 3. SHOW LOGOUT BUTTON IF LOGGED IN (INSIDE THE DIV) */
          <div className="text-center">
            <p className="text-blue-600 font-bold text-lg mb-6">{message}</p>
            <button 
              onClick={handleLogout}
              className="flex items-center justify-center w-full bg-red-500 text-white py-2 rounded-lg font-semibold hover:bg-red-600 transition duration-300"
            >
              <LogOut size={18} className="mr-2" />
              Logout
            </button>
          </div>
        )}

        {/* Show error messages here if not logged in */}
        {!isLoggedIn && message && (
          <p className="mt-4 text-center text-sm font-medium text-red-500">
            {message}
          </p>
        )}
      </div>
    </div>
  );
};

export default Login;
